require "config.Define"

GameFuncNpc = class()

GameFuncNpc.AD_Job = 1       --广告npc
GameFuncNpc.JOB_STORE = 2     --职业商店npc
GameFuncNpc.SEASON_RANK = 3    --排行榜
GameFuncNpc.AD_Prop = 4
GameFuncNpc.MODEL_SELECT = 5   --开始游戏区域
function GameFuncNpc:ctor(config)
    self.players = {}
    self.type = tonumber(config.type)
    self.name = tostring(config.name)
    self.actor = tostring(config.actor) or ""
    self.pos = VectorUtil.newVector3(config.x, config.y, config.z)
    self.yaw = tonumber(config.yaw) or 0
    self.effect = tostring(config.effect) or ""
    self:initArea(tonumber(config.range) or 1)
    self:onCreate()
end

function GameFuncNpc:initArea(range)
    self.minX = self.pos.x - range
    self.maxX = self.pos.x + range
    self.minY = self.pos.y - range
    self.maxY = self.pos.y + range
    self.minZ = self.pos.z - range
    self.maxZ = self.pos.z + range
end

function GameFuncNpc:onCreate()
    local entityId = EngineWorld:addSessionNpc(self.pos, self.yaw, 7, self.actor, function(entity)
        entity:setNameLang(self.name or "")
        if self.effect ~= "#" then
            entity:setEffectName(self.effect or "")
        end
    end)
    self.entityId = entityId
end

function GameFuncNpc:inArea(x, y, z)
    return x >= self.minX and x <= self.maxX
            and y >= self.minY and y <= self.maxY
            and z >= self.minZ and z <= self.maxZ
end

function GameFuncNpc:onPlayerMove(player, x, y, z)
    if self:inArea(x, y, z) then
        self:onPlayerEnter(player)
    else
        self:onPlayerQuit(player)
    end
end

function GameFuncNpc:onPlayerEnter(player)
    if self.players[tostring(player.userId)] ~= nil then
        return
    end

    self.players[tostring(player.userId)] = true
    self:onPlayerTriggered(player)
end

function GameFuncNpc:onPlayerTriggered(player)
    if self.type == GameFuncNpc.MODEL_SELECT then
        self:onPlayerClickNpc(player)
    elseif self.type == GameFuncNpc.AD_Job then
        GamePacketSender:sendOpenUIByType(player.rakssid, Define.UIType.AD_Job)
    elseif self.type == GameFuncNpc.AD_Prop then
        GamePacketSender:sendOpenUIByType(player.rakssid, Define.UIType.AD_Prop)
    elseif self.type == GameFuncNpc.JOB_STORE then
        GamePacketSender:sendOpenUIByType(player.rakssid, Define.UIType.Job_Store)
    elseif self.type == GameFuncNpc.SEASON_RANK then
        GamePacketSender:sendOpenUIByType(player.rakssid, Define.UIType.Rank)
    end
end

function GameFuncNpc:onPlayerClickNpc(player)
    GamePacketSender:sendCustomTip(player.rakssid, Define.StartGame)
end

function GameFuncNpc:onPlayerQuit(player)
    self.players[tostring(player.userId)] = nil
end